/**
 * @summary Get email logs
 */
export const getGetEmailLogsUrl = (params?: GetEmailLogsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/email-logs?${stringifiedParams}`
    : `/api/email-logs`;
};

export const getEmailLogs = async (
  params?: GetEmailLogsParams,
  options?: RequestInit,
): Promise<EmailLogsResponse> => {
  return customFetch<EmailLogsResponse>(getGetEmailLogsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetEmailLogsQueryKey = (params?: GetEmailLogsParams) => {
  return [`/api/email-logs`, ...(params ? [params] : [])] as const;
};

export const getGetEmailLogsQueryOptions = <
  TData = Awaited<ReturnType<typeof getEmailLogs>>,
  TError = ErrorType<unknown>,
>(
  params?: GetEmailLogsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getEmailLogs>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetEmailLogsQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getEmailLogs>>> = ({
    signal,
  }) => getEmailLogs(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getEmailLogs>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

